mapper.select:
WITH role_map AS ( /* м§Ғм ‘ + к·ёлЈ№ м—ӯн• л§Өн•‘ (мӨ‘ліө м ңкұ°) */ SELECT pru.project_code, pru.role_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code, gpr.role_code FROM group_member gm JOIN gr_pro_role gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ), /* н”„лЎңм қнҠё лӢЁмң„ admin м—¬л¶Җ */ admin_proj AS ( SELECT rm.project_code, MAX(CASE WHEN r.admin_ck = 'Y' THEN 1 ELSE 0 END) AS is_admin FROM role_map rm JOIN role r ON r.role_code = rm.role_code GROUP BY rm.project_code ), /* н”„лЎңм қнҠё мқҪкё° кІҢмқҙнҠё(м№ҙн…Ңкі лҰ¬=н”„лЎңм қнҠё rdRol=Y н•ҳлӮҳлқјлҸ„) */ proj_read AS ( SELECT rm.project_code, MAX(CASE WHEN ra.rd_rol = 'Y' THEN 1 ELSE 0 END) AS can_read_project FROM role_map rm JOIN role_authority ra ON ra.role_code = rm.role_code AND ra.category = 'н”„лЎңм қнҠё' GROUP BY rm.project_code ), /* LISTAGG м „м—җ role_name мӨ‘ліө м ңкұ° */ roles_src AS ( SELECT DISTINCT rm.project_code, r.role_name FROM role_map rm JOIN role r ON r.role_code = rm.role_code ) SELECT p.project_code AS projectCode, p.project_name AS projectName, p.status AS status, cc.code_name AS statusName, LISTAGG(rs.role_name, ', ') WITHIN GROUP (ORDER BY rs.role_name) AS roles FROM roles_src rs JOIN projects p ON p.project_code = rs.project_code LEFT JOIN common_code cc ON cc.group_code = 'OD' AND cc.code_id = p.status LEFT JOIN admin_proj ap ON ap.project_code = p.project_code LEFT JOIN proj_read pr ON pr.project_code = p.project_code WHERE p.status <> 'OD2' /* н”„лЎңм қнҠё лӘ©лЎқ л…ём¶ң кё°мӨҖ: admin мқҙкұ°лӮҳ н”„лЎңм қнҠё read к°ҖлҠҘ */ AND (NVL(ap.is_admin, 0) = 1 OR NVL(pr.can_read_project, 0) = 1) /* мў…лЈҢ(OD3)лҠ” adminл§Ң л…ём¶ң */ AND (p.status <> 'OD3' OR NVL(ap.is_admin, 0) = 1) GROUP BY p.project_code, p.project_name, p.status, cc.code_name ORDER BY p.project_name
